sql:
SELECT name, height
FROM pokemon_species
WHERE height = (SELECT MAX(height) FROM pokemon_species);

SELECT name
FROM pokemon_species
WHERE habitat_id = (SELECT habitat_id FROM habitats WHERE habitat_name = 'Grassland');

external_knowledge:
- 'Powerful Pokémon' refers to Pokémon with base experience points greater than 100; 
- 'most powerful evolved Pokémon' refers to the evolved Pokémon with the highest base experience points;
- 'powerful ancestor' refers to the parent Pokémon in the evolution chain with base experience points greater than 100.
